oldWay:
/* Same value copy-pasted everywhere */
.button { background: #a855f7; }
.badge  { background: #a855f7; border-color: #a855f7; }
.link   { color: #a855f7; }
/* To rebrand: grep-and-replace across the entire stylesheet */

modernWay:
:root {
  --brand: #a855f7;
}

.button { background: var(--brand); }
.badge  { background: var(--brand); }
.link   { color: var(--brand); }

startingCSS:
.container {
  display: flex;
  gap: 1rem;
  align-items: center;
  padding: 1.5rem;
  background: #1e293b;
  border-radius: 10px;
  /* Define --brand-color here */
}

.button {
  background: var(--brand-color, #475569);
  color: white;
  border: none;
  padding: 0.625rem 1.25rem;
  border-radius: 6px;
  font-weight: 600;
  font-size: 0.9rem;
  cursor: pointer;
}

.badge {
  background: var(--brand-color, #475569);
  color: white;
  padding: 0.2rem 0.6rem;
  border-radius: 999px;
  font-size: 0.75rem;
  font-weight: 600;
}
